from typing import List


class Solution:
    def removeStones(self, stones: List[List[int]]) -> int:
        if not stones:
            return 0

        parent = {}

        def find(node: int) -> int:
            parent.setdefault(node, node)
            # path compression
            root = node
            while parent[root] != root:
                root = parent[root]
            while parent[node] != root:
                parent[node], node = root, parent[node]
            return root

        def union(a: int, b: int) -> None:
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb

        COL_OFFSET = 10001
        for x, y in stones:
            union(x, y + COL_OFFSET)

        roots = {find(node) for node in parent}
        return len(stones) - len(roots)


# ---- Brute force oracle: explicit graph + DFS ----
class BruteForce:
    def removeStones(self, stones: List[List[int]]) -> int:
        n = len(stones)
        if n == 0:
            return 0
        adj = {i: [] for i in range(n)}
        for i in range(n):
            for j in range(i + 1, n):
                if stones[i][0] == stones[j][0] or stones[i][1] == stones[j][1]:
                    adj[i].append(j)
                    adj[j].append(i)
        seen = set()
        comps = 0
        for i in range(n):
            if i not in seen:
                comps += 1
                stack = [i]
                while stack:
                    cur = stack.pop()
                    if cur in seen:
                        continue
                    seen.add(cur)
                    stack.extend(adj[cur])
        return n - comps


def test():
    sol, bf = Solution(), BruteForce()
    cases = [
        ([[0,0],[0,1],[1,0],[1,2],[2,1],[2,2]], 5),
        ([[0,0],[0,2],[1,1],[2,0],[2,2]], 3),
        ([[0,0]], 0),
        ([[0,0],[1,1]], 0),          # two isolated
        ([[0,0],[0,1]], 1),          # share row
        ([[0,0],[1,0]], 1),          # share column
        ([], 0),
    ]
    for stones, expected in cases:
        got = sol.removeStones([s[:] for s in stones])
        assert got == expected, f"FAIL {stones}: got {got}, want {expected}"
    print("explicit cases passed")

    # random stress vs brute force
    import random
    for _ in range(3000):
        coords = random.sample([(x, y) for x in range(6) for y in range(6)],
                               k=random.randint(0, 10))
        stones = [list(c) for c in coords]
        a = sol.removeStones([s[:] for s in stones])
        b = bf.removeStones([s[:] for s in stones])
        assert a == b, f"MISMATCH {stones}: opt {a}, brute {b}"
    print("3000 random cases match brute force")

    # max-size stress
    import time
    big = [[x, y] for x in range(32) for y in range(32)]  # 1024 stones
    t = time.time()
    print("max stress answer:", sol.removeStones(big), "in", round(time.time()-t, 4), "s")


test()
